final:
module RefModule(
		input [4 * WIDTH - 1:0] in,
		input [1:0] select,
		output [WIDTH - 1:0] out
		);parameter WIDTH = 1;

	wire __select_tmp = select == 2'b00;
	assign out = __select_tmp ? in[WIDTH - 1:0] : select == 2'b01 ? in[2 * WIDTH - 1: WIDTH] :
			select == 2'b10 ? in[3 * WIDTH - 1: 2 * WIDTH] :
			in[4 * WIDTH - 1: 3 * WIDTH];
endmodule
